{
  "model": "llama3",
  "messages": [
    {
      "role": "system",
      "content": "You are a reasoning agent. Answer the user's question. You have access to the following tools:\n- get_weather({\"location\": \"string\"}): gets the weather.\nUse the following format:\nThought: think about what to do\nAction: tool_name\nAction Input: tool_arguments_in_json\nObservation: tool_result\n... (this Thought/Action/Observation can repeat N times)\nThought: I now know the final answer\nFinal Answer: the final answer to the original input question."
    },
    {
      "role": "user",
      "content": "What is the capital of France, and what is its current temperature?"
    }
  ],
  "stream": false
}
